using System;
using System.Data.SqlClient;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;

public static class SqlQueryFunction
{
    [FunctionName("SqlQueryFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("AzureSqlConnection");

        if (string.IsNullOrEmpty(connectionString))
        {
            return new BadRequestObjectResult("Connection String not set.");
        }

        string tableName = req.Query["tableName"];
        string selectColumns = req.Query["columns"] ?? "*";
        string whereClause = req.Query["where"];

        if (string.IsNullOrEmpty(tableName))
        {
            return new BadRequestObjectResult("Table name is required.");
        }

        string query = $"SELECT {selectColumns} FROM {tableName}";

        if (!string.IsNullOrEmpty(whereClause))
        {
            query += $" WHERE {whereClause}";
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                await connection.OpenAsync();
                using (SqlCommand command = new SqlCommand(query, connection))
                {
                    SqlDataReader reader = await command.ExecuteReaderAsync();

                    var results = new List<Dictionary<string, object>>();
                    while (await reader.ReadAsync())
                    {
                        var row = new Dictionary<string, object>();
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            row[reader.GetName(i)] = reader[i];
                        }
                        results.Add(row);
                    }

                    return new OkObjectResult(JsonConvert.SerializeObject(results));
                }
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error executing SQL query.");
                return new StatusCodeResult(500);
            }
        }
    }
}